class Solution:
    def applyOperations(self, nums):
        a = list(nums)
        for i in range(len(a) - 1):
            if a[i] == a[i + 1]:
                a[i] *= 2
                a[i + 1] = 0
        nonzero = [x for x in a if x != 0]
        zeros = [0] * (len(a) - len(nonzero))
        return nonzero + zeros

solutions.python:
class Solution:
    def applyOperations(self, nums):
        n = len(nums)
        for i in range(n - 1):
            if nums[i] == nums[i + 1]:
                nums[i] <<= 1
                nums[i + 1] = 0
        out = []
        for x in nums:
            if x != 0:
                out.append(x)
        out.extend([0] * (n - len(out)))
        return out

