var applyOperations = function(nums) {
    const n = nums.length;
    for (let i = 0; i < n - 1; i++) {
        if (nums[i] === nums[i + 1]) {
            nums[i] *= 2;
            nums[i + 1] = 0;
        }
    }
    const out = [];
    for (const x of nums) if (x !== 0) out.push(x);
    while (out.length < n) out.push(0);
    return out;
};
